/**
 * @fileoverview MarkdownEditor view — DOM construction, toolbar, context menu,
 *               preview / status updates, and history popups.
 * @module module/MarkdownEditor/view
 */

import {
    TOOLBAR_ITEMS,
    CONTEXT_MENU_ITEMS,
    MODE_BUTTONS,
    getCustomTools,
} from './constants.js';
import { parse, escapeHtml, htmlToMarkdown } from './helpers.js';
import { renderMathInElement } from './katexMath.js';
import razyui from '../../index.js';
import Icons from '../Icons.js';
import { PART } from './constants.js';

// ═══════════════════════════════════════════════════
// DOM Construction
// ═══════════════════════════════════════════════════

/**
 * Build the complete editor DOM and mount it into the target element.
 * Sets ctx.container, ctx.toolbar, ctx.editorPane, ctx.previewPane,
 * ctx.textarea, ctx.preview, ctx.statusBar.
 *
 * @param {object} ctx — context bridge
 */
export function buildDOM(ctx) {
    const cfg = ctx.config;
    const el  = ctx.target;
    const stateRef = ctx.stateRef;

    // ── Container ──
    const container = razyui.el('div', { className: `markdown-editor md-editor mode-${stateRef.mode}${cfg.lite ? ' is-lite' : ''}` });
    PART.ROOT.apply(container);
    if (cfg.height && cfg.height !== 'auto') {
        container.css('height', cfg.height);
    } else if (cfg.minHeight && !cfg.lite) {
        // Set definite height so nested flex children (body → pane → textarea)
        // can properly resolve their sizes in editor-only / preview-only modes
        container.css('height', cfg.minHeight);
    }
    if (cfg.minHeight && !cfg.lite) container.css('min-height', cfg.minHeight);
    ctx.container = container;

    // ── Toolbar (skip in lite mode) ──
    if (cfg.toolbar !== false && !cfg.lite) {
        ctx.toolbar = buildToolbar(ctx);
        container.append(ctx.toolbar);
    }

    // ── Body ──
    const body = razyui.el('div', { className: 'md-body' });
    PART.BODY.apply(body);

    if (cfg.lite) {
        // WYSIWYG: single contenteditable div, no textarea
        const previewPane = razyui.el('div', { className: 'md-pane md-preview-pane' });
        const preview = razyui.el('div', { className: 'md-preview', contentEditable: 'true', innerHTML: stateRef.markdown ? parse(stateRef.markdown) : '' });
        PART.PREVIEW.apply(preview);
        if (stateRef.markdown) void renderMathInElement(preview[0]);
        if (!stateRef.markdown) {
            preview.attr('data-placeholder', cfg.placeholder);
        }
        previewPane.append(preview);
        ctx.preview = preview;
        ctx.previewPane = previewPane;
        body.append(previewPane);
        ctx.textarea = null;
        ctx.editorPane = null;
    } else {
        // Standard: editor pane (textarea) + preview pane
        const editorPane = razyui.el('div', { className: 'md-pane md-editor-pane' });
        PART.PANE.apply(editorPane);
        const textarea = razyui.el('textarea', { className: 'md-textarea', placeholder: cfg.placeholder, value: stateRef.markdown, spellcheck: false });
        PART.TEXTAREA.apply(textarea);
        editorPane.append(textarea);
        ctx.textarea = textarea;
        ctx.editorPane = editorPane;
        body.append(editorPane);

        const previewPane = razyui.el('div', { className: 'md-pane md-preview-pane' });
        PART.PANE.apply(previewPane);
        const preview = razyui.el('div', { className: 'md-preview' });
        PART.PREVIEW.apply(preview);
        previewPane.append(preview);
        ctx.preview = preview;
        ctx.previewPane = previewPane;
        body.append(previewPane);
    }

    container.append(body);

    // ── Status bar (skip in lite mode) ──
    if (!cfg.lite) {
        const status = razyui.el('div', { className: 'md-status' });
        PART.STATUSBAR.apply(status);
        ctx.statusBar = status;
        container.append(status);
    }

    // ── Mount ──
    if (el.tagName === 'TEXTAREA') {
        razyui(el).css('display', 'none');
        el.insertAdjacentElement('afterend', container[0]);
    } else {
        razyui(el).append(container[0]);
    }
}

// ═══════════════════════════════════════════════════
// Toolbar
// ═══════════════════════════════════════════════════

/**
 * Build the toolbar element.
 * @param {object} ctx — context bridge
 * @returns {HTMLElement}
 */
export function buildToolbar(ctx) {
    const bar = razyui.el('div', { className: 'md-toolbar' });
    PART.TOOLBAR.apply(bar);

    // Prevent toolbar clicks from stealing contenteditable focus
    bar.on('mousedown', (e) => {
        if (e.target.closest('.md-toolbar-btn')) e.preventDefault();
    });

    TOOLBAR_ITEMS.forEach(item => {
        if (item === 'sep') {
            const sep = razyui.el('span', { className: 'md-toolbar-sep' });
            PART.TOOLBAR_SEP.apply(sep);
            bar.append(sep);
            return;
        }
        const btn = razyui.el('button', { type: 'button', className: 'md-toolbar-btn', title: item.title || '', innerHTML: item.label, 'data-action': item.action });
        PART.TOOLBAR_BTN.apply(btn);
        if (item.css) btn.attr('style', item.css);
        bar.append(btn);
    });

    // ── Custom plugin tools ──
    const customTools = getCustomTools();
    if (customTools.length) {
        const sep = razyui.el('span', { className: 'md-toolbar-sep' });
        PART.TOOLBAR_SEP.apply(sep);
        bar.append(sep);

        customTools.forEach(tool => {
            const btn = razyui.el('button', { type: 'button', className: 'md-toolbar-btn', title: tool.title || '', innerHTML: tool.label, 'data-action': tool.action });
            PART.TOOLBAR_BTN.apply(btn);
            if (tool.css) btn.attr('style', tool.css);
            bar.append(btn);
        });
    }

    // ── Spacer ──
    const spacer = razyui.el('span');
    spacer.css('flex', '1');
    bar.append(spacer);

    // ── Mode toggle group ──
    MODE_BUTTONS.forEach(m => {
        const btn = razyui.el('button', { type: 'button', className: 'md-toolbar-btn md-mode-btn', title: m.title, innerHTML: m.label, 'data-mode': m.mode });
        PART.TOOLBAR_BTN.apply(btn);
        if (m.mode === ctx.config.mode) btn.addClass('is-active');
        bar.append(btn);
    });

    // ── History dropdown ──
    if (ctx.config.historyKey) {
        const histWrap = razyui.el('span', { className: 'md-history-menu-wrap' });
        PART.HISTORY_WRAP.apply(histWrap);
        const histBtn = razyui.el('button', { type: 'button', className: 'md-toolbar-btn', title: 'History', innerHTML: Icons.svg('clipboard', { size: 16, strokeWidth: 1.5 }), 'data-role': 'history-toggle' });
        PART.TOOLBAR_BTN.apply(histBtn);
        const menu = razyui.el('div', { className: 'md-history-menu' });
        PART.HISTORY_MENU.apply(menu);
        const histItems = [
            { action: 'save', icon: 'save', label: 'Save Now' },
            { action: 'manage', icon: 'book', label: 'Manage History' },
            { action: 'restore', icon: 'rotate-ccw', label: 'Restore Latest' },
            { action: 'clear', icon: 'trash-2', label: 'Clear History', danger: true },
        ];
        histItems.forEach(hi => {
            const hBtn = razyui.el('button', { type: 'button', className: `md-history-menu-item${hi.danger ? ' is-danger' : ''}`, 'data-history': hi.action });
            PART.HISTORY_ITEM.apply(hBtn);
            hBtn.html(`${Icons.svg(hi.icon, { size: 14, strokeWidth: 1.5 })} ${hi.label}`);
            menu.append(hBtn);
        });
        histWrap.append(histBtn).append(menu);
        bar.append(histWrap);
    }

    // ── Fullscreen ──
    const fsBtn = razyui.el('button', { type: 'button', className: 'md-toolbar-btn', title: 'Fullscreen', innerHTML: Icons.svg('maximize-2', { size: 16, strokeWidth: 1.5 }), 'data-role': 'fullscreen' });
    PART.TOOLBAR_BTN.apply(fsBtn);
    bar.append(fsBtn);

    return bar;
}

// ═══════════════════════════════════════════════════
// Context Menu (right-click)
// ═══════════════════════════════════════════════════

/**
 * Build the context menu element.
 * @param {object} ctx — context bridge
 * @returns {HTMLElement}
 */
export function buildContextMenu(ctx) {
    const menu = razyui.el('div', { className: 'md-context-menu' });
    PART.CONTEXT_MENU.apply(menu);
    menu.on('mousedown', (e) => e.preventDefault());

    CONTEXT_MENU_ITEMS.forEach(item => {
        if (item === 'sep') {
            const sep = razyui.el('div', { className: 'md-context-sep' });
            PART.CTX_SEP.apply(sep);
            menu.append(sep);
            return;
        }
        const btn = razyui.el('button', { type: 'button', className: 'md-context-item', innerHTML: item.label, 'data-action': item.action });
        PART.CTX_ITEM.apply(btn);
        menu.append(btn);
    });

    // ── Custom plugin tools ──
    const customTools = getCustomTools();
    if (customTools.length) {
        const sep = razyui.el('div', { className: 'md-context-sep' });
        PART.CTX_SEP.apply(sep);
        menu.append(sep);

        customTools.forEach(tool => {
            const btn = razyui.el('button', { type: 'button', className: 'md-context-item', innerHTML: tool.menuLabel || tool.label, 'data-action': tool.action });
            PART.CTX_ITEM.apply(btn);
            menu.append(btn);
        });
    }

    return menu;
}

/**
 * Show the context menu at the given coordinates.
 * Lazily creates the menu on first use.
 * @param {object} ctx
 * @param {number} x
 * @param {number} y
 */
export function showContextMenu(ctx, x, y) {
    if (!ctx.contextMenu) {
        ctx.contextMenu = buildContextMenu(ctx);
        ctx.container.append(ctx.contextMenu);
    }

    const menu = ctx.contextMenu;
    // Position just off-screen temporarily to measure
    menu.css('left', '0')
        .css('top', '0');
    menu.css('display', 'block');

    // Calculate position relative to the container
    const containerRect = ctx.container.getRect();
    let relX = x - containerRect.left;
    let relY = y - containerRect.top;

    // Measure menu and clamp within container bounds
    const mW = menu.prop('offsetWidth');
    const mH = menu.prop('offsetHeight');
    const cW = containerRect.width;
    const cH = containerRect.height;

    if (relX + mW > cW) relX = Math.max(0, cW - mW - 4);
    if (relY + mH > cH) relY = Math.max(0, relY - mH);

    menu.css('left', relX + 'px')
        .css('top', relY + 'px');
}

/**
 * Hide the context menu.
 * @param {object} ctx
 */
export function hideContextMenu(ctx) {
    if (ctx.contextMenu) {
        ctx.contextMenu.css('display', 'none');
    }
}

// ═══════════════════════════════════════════════════
// Preview & Status Updates
// ═══════════════════════════════════════════════════

/**
 * Re-render the preview pane from the current Markdown state.
 * @param {object} ctx
 */
export function updatePreview(ctx) {
    if (ctx.config.lite || ctx.stateRef.mode === 'wysiwyg') return;
    ctx.preview.html(parse(ctx.stateRef.markdown));
    void renderMathInElement(ctx.preview[0]);
}

/**
 * Update the status bar word / line / character count.
 * @param {object} ctx
 */
export function updateStatus(ctx) {
    if (!ctx.statusBar) return;
    const md = ctx.stateRef.markdown;
    const chars = md.length;
    const words = md.trim() ? md.trim().split(/\s+/).length : 0;
    const lineCount = md.split('\n').length;
    ctx.statusBar.text(`${words} words \u00B7 ${lineCount} lines \u00B7 ${chars} chars`);
}

// ═══════════════════════════════════════════════════
// History Restore Popup (init-time)
// ═══════════════════════════════════════════════════

/**
 * Show a darkroom overlay inside the editor for snapshot restore.
 * Called on init when autoSave is enabled and snapshots exist.
 * Uses Combobox components for set and snapshot pickers.
 *
 * @param {object} ctx — context bridge
 */
export async function showHistoryRestorePopup(ctx) {
    const book = ctx.readBook();
    const setIds = Object.keys(book.sets).filter(id => book.sets[id].snapshots.length > 0);
    if (!setIds.length) return;

    const razyui = ctx.razyui;
    const Combobox = await razyui.load('Combobox');
    let activeSetId = String(book.activeSet ?? 0);
    if (!setIds.includes(activeSetId)) activeSetId = setIds[0];

    // Ensure container is positioned for absolute overlay
    const containerPos = getComputedStyle(ctx.container[0]).position;
    if (containerPos === 'static' || !containerPos) {
        ctx.container.css('position', 'relative');
    }

    // ── Darkroom overlay ──
    const overlay = razyui.el('div', { className: 'md-restore-overlay' });

    const panel = razyui.el('div', { className: 'md-restore-panel' });

    // ── Info header ──
    const totalSnaps = setIds.reduce((n, id) => n + book.sets[id].snapshots.length, 0);
    const header = razyui.el('div', {
        className: 'md-restore-header',
        innerHTML: '<span class="md-restore-icon">' + Icons.svg('book', { size: 16, strokeWidth: 1.5 }) + '</span> <strong>' + totalSnaps +
            '</strong> snapshot' + (totalSnaps > 1 ? 's' : '') +
            (setIds.length > 1 ? (' across ' + setIds.length + ' sets') : '') +
            ' found',
    });
    panel.append(header);

    // ── Pickers row ──
    const pickersRow = razyui.el('div', { className: 'md-restore-pickers' });

    // Set picker (only if > 1 set)
    if (setIds.length > 1) {
        const setNative = razyui.el('select');
        setIds.forEach(id => {
            const s = book.sets[id];
            const opt = razyui.el('option', { value: id, textContent: `${s.name || 'Set ' + id} (${s.snapshots.length})` });
            setNative.append(opt);
        });
        setNative.val(activeSetId);
        pickersRow.append(setNative);
        new Combobox(setNative[0], {
            placeholder: 'Select set\u2026',
            onSelect(val) {
                activeSetId = val;
                rebuildSnapshotOptions();
            },
        });
    }

    // Snapshot picker
    const snapNative = razyui.el('select');
    pickersRow.append(snapNative);
    const snapCombobox = new Combobox(snapNative[0], {
        placeholder: 'Select snapshot\u2026',
    });
    panel.append(pickersRow);

    // ── Preview area ──
    const preview = razyui.el('div', { className: 'md-restore-preview', textContent: '' });
    panel.append(preview);

    const updatePreviewText = () => {
        const snaps = book.sets[activeSetId]?.snapshots || [];
        const val = snapCombobox.getValue();
        const idx = parseInt(val, 10);
        if (!isNaN(idx) && snaps[idx]) {
            const md = snaps[idx].md;
            preview.text(md.length > 300 ? md.substring(0, 300) + '\u2026' : md);
        } else {
            preview.text('');
        }
    };

    // Wire snapshot change to update preview (via delegation)
    snapNative.data('role', 'snap-select');

    const rebuildSnapshotOptions = () => {
        const snaps = book.sets[activeSetId]?.snapshots || [];
        const opts = snaps.map((entry, i) => {
            const date = new Date(entry.ts).toLocaleString();
            const pv = entry.md.substring(0, 50).replace(/\n/g, ' ');
            return {
                value: String(i),
                text: `[${i + 1}] ${date} \u2014 ${pv}${entry.md.length > 50 ? '\u2026' : ''}`,
            };
        });
        snapCombobox.setOptions(opts);
        if (opts.length) {
            snapCombobox.setValue(String(opts.length - 1));
        }
        updatePreviewText();
    };

    rebuildSnapshotOptions();

    // ── Action buttons ──
    const actions = razyui.el('div', { className: 'md-restore-actions' });

    const restoreBtn = razyui.el('button', { type: 'button', className: 'md-restore-btn md-restore-primary', textContent: 'Restore', 'data-role': 'restore' });

    const manageBtn = razyui.el('button', { type: 'button', className: 'md-restore-btn md-restore-secondary', textContent: 'Manage', 'data-role': 'manage' });

    const dismissBtn = razyui.el('button', { type: 'button', className: 'md-restore-btn md-restore-ghost', textContent: 'Start Fresh', 'data-role': 'dismiss' });

    actions.append(restoreBtn)
           .append(manageBtn);
    actions.append(dismissBtn);
    panel.append(actions);

    overlay.append(panel);

    // ── Delegated events ──
    ctx.bindHistoryRestoreEvents(overlay, {
        book,
        getActiveSetId: () => activeSetId,
        snapCombobox,
        updatePreviewText,
    });

    ctx.container.append(overlay);
}

// ═══════════════════════════════════════════════════
// History Manager Popup
// ═══════════════════════════════════════════════════

/**
 * Show a Dialog for managing history: view/delete snapshots, manage sets.
 * @param {object} ctx — context bridge
 */
export async function showHistoryManagerPopup(ctx) {
    const razyui = ctx.razyui;
    const Dialog = await razyui.load('Dialog');

    let book = ctx.readBook();
    const setIds = () => Object.keys(book.sets);

    if (!setIds().length || setIds().every(id => !book.sets[id].snapshots.length)) {
        Dialog.alert(Icons.svg('book', { size: 18, strokeWidth: 1.5 }) + ' History Manager', 'No history entries found.');
        return;
    }

    const wrap = razyui.el('div');
    let activeTab = String(book.activeSet ?? 0);

    const renderAll = () => {
        book = ctx.readBook();
        wrap.html('');
        const ids = setIds();

        // ── Set tabs ──
        if (ids.length > 0) {
            const tabBar = razyui.el('div', { className: 'md-hm-tabs' });

            ids.forEach(id => {
                const s = book.sets[id];
                const tab = razyui.el('button', { type: 'button', className: 'md-hm-tab' + (id === activeTab ? ' is-active' : ''), textContent: `${s.name || 'Set ' + id} (${s.snapshots.length})`, 'data-role': 'tab', 'data-set-id': id });
                tabBar.append(tab);
            });

            // New set button
            const addBtn = razyui.el('button', { type: 'button', className: 'md-hm-tab md-hm-tab-add', innerHTML: Icons.svg('plus', { size: 14, strokeWidth: 2 }), title: 'Create new set', 'data-role': 'add-set' });
            tabBar.append(addBtn);

            wrap.append(tabBar);
        }

        // ── Active set info ──
        const activeSet = book.sets[activeTab];
        if (!activeSet) {
            wrap.append('<p class="md-hm-empty">Set not found.</p>');
            return;
        }

        const info = razyui.el('div', { className: 'md-hm-info' });
        const isActive = String(book.activeSet) === activeTab;
        info.html('<strong>' + escapeHtml(activeSet.name || 'Set ' + activeTab) + '</strong>' +
            '<span class="md-hm-meta">\u2014 ' + activeSet.snapshots.length + ' snapshot' +
            (activeSet.snapshots.length !== 1 ? 's' : '') + '</span>' +
            (isActive ? '<span class="md-hm-active-badge">\u25cf active</span>' : ''));

        // Set action buttons
        const setActions = razyui.el('span', { className: 'md-hm-set-actions' });

        if (!isActive) {
            const switchBtn = razyui.el('button', { type: 'button', className: 'md-hm-btn md-hm-btn-accent', textContent: 'Set Active', title: 'Make this the active set for auto-save', 'data-role': 'switch-set' });
            setActions.append(switchBtn);
        }

        const renameBtn = razyui.el('button', { type: 'button', className: 'md-hm-btn', innerHTML: Icons.svg('square-pen', { size: 14, strokeWidth: 1.5 }), title: 'Rename set', 'data-role': 'rename-set' });
        setActions.append(renameBtn);

        if (ids.length > 1) {
            const delSetBtn = razyui.el('button', { type: 'button', className: 'md-hm-btn md-hm-btn-danger', innerHTML: Icons.svg('trash-2', { size: 14, strokeWidth: 1.5 }), title: 'Delete this set', 'data-role': 'delete-set' });
            setActions.append(delSetBtn);
        }

        info.append(setActions);
        wrap.append(info);

        // ── Snapshot list ──
        if (!activeSet.snapshots.length) {
            const empty = razyui.el('p', { className: 'md-hm-empty', textContent: 'No snapshots in this set.' });
            wrap.append(empty);
            return;
        }

        const list = razyui.el('div', { className: 'md-hm-list' });

        activeSet.snapshots.forEach((entry, i) => {
            const row = razyui.el('div', { className: 'md-hm-row' });

            const content = razyui.el('div', { className: 'md-hm-row-content' });
            const date = new Date(entry.ts).toLocaleString();
            const pvText = entry.md.substring(0, 80).replace(/\n/g, ' ');
            content.html('<strong class="md-hm-date">' +
                date + '</strong> <span class="md-hm-chars">(' +
                entry.md.length + ' chars)</span><br>' +
                '<span class="md-hm-preview-text">' +
                escapeHtml(pvText) +
                (entry.md.length > 80 ? '\u2026' : '') + '</span>');

            const btnGroup = razyui.el('div', { className: 'md-hm-row-actions' });

            const restoreBtn = razyui.el('button', { type: 'button', className: 'md-hm-btn md-hm-btn-accent', innerHTML: Icons.svg('rotate-ccw', { size: 14, strokeWidth: 1.5 }), title: 'Restore this snapshot', 'data-role': 'restore-snap', 'data-index': String(i) });

            const delBtn = razyui.el('button', { type: 'button', className: 'md-hm-btn md-hm-btn-danger', innerHTML: Icons.svg('trash-2', { size: 14, strokeWidth: 1.5 }), title: 'Delete this snapshot', 'data-role': 'delete-snap', 'data-index': String(i) });

            btnGroup.append(restoreBtn)
                    .append(delBtn);
            row.append(content)
               .append(btnGroup);
            list.append(row);
        });

        wrap.append(list);
    };

    renderAll();

    // ── Delegated events (survives re-renders) ──
    ctx.bindHistoryManagerEvents(wrap, {
        Dialog,
        getBook: () => ctx.readBook(),
        getActiveTab: () => activeTab,
        setActiveTab: (id) => { activeTab = id; },
        renderAll,
        getPopupCtrl: () => popupCtrl,
    });

    let popupCtrl = null;
    const inst = new Dialog({
        title: Icons.svg('book', { size: 18, strokeWidth: 1.5 }) + ' History Manager',
        content: wrap[0],
        size: 'lg',
        buttons: [
            {
                text: Icons.svg('trash-2', { size: 14, strokeWidth: 1.5 }) + ' Clear Set',
                color: 'danger',
                close: false,
                action: async () => {
                    const ok = await Dialog.confirm('Clear Snapshots', 'Delete all snapshots in this set?');
                    if (ok) {
                        const s = book.sets[activeTab];
                        if (s) s.snapshots = [];
                        ctx.writeBook(book);
                        renderAll();
                    }
                },
            },
            { text: 'Close', color: 'muted', role: 'cancel' },
        ],
    });
    popupCtrl = inst.getControl();
}
