// ── Plugin tools registry (module-level) ─────────
let _customTools = [];

/**
 * Register a custom toolbar/context-menu tool.
 * @param {object} config
 * @param {string} config.action    — unique action identifier
 * @param {string} config.label     — button label (HTML allowed)
 * @param {string} [config.title]   — tooltip text
 * @param {string} [config.css]     — inline CSS for the toolbar button
 * @param {string} [config.menuLabel] — label for context menu (HTML, defaults to label)
 * @param {function} config.handler — (editorInstance) => void
 */
export function registerTool(config) {
    if (!config || !config.action) return;
    _customTools = _customTools.filter(t => t.action !== config.action);
    _customTools.push(config);
}

/**
 * Remove a registered custom tool by action name.
 * @param {string} action
 */
export function unregisterTool(action) {
    _customTools = _customTools.filter(t => t.action !== action);
}

/**
 * Get all registered custom tools (live reference — internal use).
 * @returns {Array}
 */
export function getCustomTools() {
    return _customTools;
}

/**
 * Get a read-only copy of registered custom tools.
 * @returns {Array}
 */
export function getCustomToolsCopy() {
    return _customTools.map(t => ({ ...t }));
}

