/**
 * @fileoverview MarkdownEditor component — modular entry point.
 *
 * Orchestrates sub-modules:
 *   constants.js — CSS classes, config defaults, toolbar / menu definitions
 *   helpers.js   — pure Markdown parsing / conversion utilities
 *   state.js     — reactive state creation, auto-save / history management
 *   view.js      — DOM construction, toolbar, preview, history popups
 *   events.js    — centralised event binding, keyboard shortcuts, actions
 *
 * @module module/MarkdownEditor
 */

import { default as razyui } from '../../index.js';

// ── Sub-module imports ──
import {
    DEFAULTS,
    registerTool,
    unregisterTool,
    getCustomToolsCopy,
} from './constants.js';
import {
    parseInline,
    parse,
    tokenize,
    htmlToMarkdown,
    escapeHtml,
} from './helpers.js';
import {
    createReactiveState,
    readBook,
    writeBook,
    readHistory,
    pushHistoryEntry,
    deleteHistoryEntry,
    clearActiveHistory,
    startAutoSave,
    stopAutoSave,
} from './state.js';
import {
    buildDOM,
    updatePreview,
    updateStatus,
    showContextMenu,
    hideContextMenu,
    showHistoryRestorePopup,
    showHistoryManagerPopup,
} from './view.js';
import {
    bindEvents,
    handleAction,
    onInput,
    onWysiwygInput,
    saveSelection,
    restoreSelection,
    wrapSelection,
    toggleLinePrefix,
    wrapBlock,
    insertAtCursor,
    wysiwygInsertText,
    wysiwygInsertHTML,
    setMode,
    toggleFullscreen,
    getCurrentMarkdown,
    applyMarkdown,
    bindHistoryRestoreEvents,
    bindHistoryManagerEvents,
} from './events.js';

/**
 * MarkdownEditor — v2
 *
 * A split-pane Markdown editor with live preview, formatting toolbar,
 * keyboard shortcuts, and a built-in lightweight Markdown parser.
 * Zero external dependencies.
 *
 * Features:
 *   - Three view modes: editor-only, split (side-by-side), preview-only
 *   - Toolbar with formatting buttons (bold, italic, headings, lists, etc.)
 *   - Built-in Markdown parser (headings, bold, italic, code, lists, tables,
 *     blockquotes, images, task lists, horizontal rules)
 *   - Keyboard shortcuts (Ctrl+B, Ctrl+I, Ctrl+K, Ctrl+E, Ctrl+S)
 *   - Synchronized scroll between editor and preview
 *   - Word / line / character count in status bar
 *   - Fullscreen toggle
 *   - Programmatic API via getControl()
 *   - Reactive state via razyui.state()
 *   - Callbacks: onChange, onSave
 *
 * Static API:
 *   MarkdownEditor.parse(markdown)       → HTML string
 *   MarkdownEditor.tokenize(markdown)    → Block token array (used by BlockEditor)
 *   MarkdownEditor.parseInline(text)     → Inline-rendered HTML string
 */
const MarkdownEditor = class {
    // -------------------------------------------------------------------------
    // Private fields
    // -------------------------------------------------------------------------
    #target = null;
    #container = null;
    #toolbar = null;
    #editorPane = null;
    #previewPane = null;
    #textarea = null;
    #preview = null;
    #statusBar = null;
    #contextMenu = null;
    #savedRange = null;
    #config = {};
    #stateRef = null;
    #setState = null;
    #updateTimer = null;
    #autoSaveTimer = null;
    #destroyed = false;

    // -------------------------------------------------------------------------
    // Static API (delegates to sub-modules)
    // -------------------------------------------------------------------------
    static parseInline = parseInline;
    static parse = parse;
    static tokenize = tokenize;
    static htmlToMarkdown = htmlToMarkdown;
    static registerTool = registerTool;
    static unregisterTool = unregisterTool;
    static get customTools() { return getCustomToolsCopy(); }

    // -------------------------------------------------------------------------
    // Context bridge (cached)
    // -------------------------------------------------------------------------
    #_ctx = null;
    #eventAC = new AbortController();
    #ctx() {
        if (!this.#_ctx) {
            const self = this;
            const ctx = {
                razyui,

                // -------------------------------------------------------------------------
                // AbortController signal
                // -------------------------------------------------------------------------
                get signal() { return self.#eventAC.signal; },

                // ── Config (read-only) ──
                get config() { return self.#config; },

                // ── DOM refs (read / write) ──
                get target()       { return self.#target; },
                get container()    { return self.#container; },
                set container(v)   { self.#container = v; },
                get toolbar()      { return self.#toolbar; },
                set toolbar(v)     { self.#toolbar = v; },
                get editorPane()   { return self.#editorPane; },
                set editorPane(v)  { self.#editorPane = v; },
                get previewPane()  { return self.#previewPane; },
                set previewPane(v) { self.#previewPane = v; },
                get textarea()     { return self.#textarea; },
                set textarea(v)    { self.#textarea = v; },
                get preview()      { return self.#preview; },
                set preview(v)     { self.#preview = v; },
                get statusBar()    { return self.#statusBar; },
                set statusBar(v)   { self.#statusBar = v; },
                get contextMenu()  { return self.#contextMenu; },
                set contextMenu(v) { self.#contextMenu = v; },
                get savedRange()   { return self.#savedRange; },
                set savedRange(v)  { self.#savedRange = v; },

                // ── Reactive state ──
                get stateRef()  { return self.#stateRef; },
                set stateRef(v) { self.#stateRef = v; },
                get setState()  { return self.#setState; },
                set setState(v) { self.#setState = v; },

                // ── Timers ──
                get updateTimer()    { return self.#updateTimer; },
                set updateTimer(v)   { self.#updateTimer = v; },
                get autoSaveTimer()  { return self.#autoSaveTimer; },
                set autoSaveTimer(v) { self.#autoSaveTimer = v; },

                // ── Flags ──
                get destroyed()  { return self.#destroyed; },
                set destroyed(v) { self.#destroyed = v; },

                // ── Instance ref (for custom tool handlers) ──
                get instance() { return self; },
            };

            // ── Bridge methods (bound once) ──
            ctx.handleAction          = (action) => handleAction(ctx, action);
            ctx.onInput               = ()       => onInput(ctx);
            ctx.onWysiwygInput        = ()       => onWysiwygInput(ctx);
            ctx.saveSelection         = ()       => saveSelection(ctx);
            ctx.restoreSelection      = ()       => restoreSelection(ctx);
            ctx.wrapSelection         = (b, a)   => wrapSelection(ctx, b, a);
            ctx.toggleLinePrefix      = (p)      => toggleLinePrefix(ctx, p);
            ctx.wrapBlock             = (b, a)   => wrapBlock(ctx, b, a);
            ctx.insertAtCursor        = (t)      => insertAtCursor(ctx, t);
            ctx.wysiwygInsertText     = (t)      => wysiwygInsertText(ctx, t);
            ctx.wysiwygInsertHTML     = (h)      => wysiwygInsertHTML(ctx, h);
            ctx.showContextMenu       = (x, y)   => showContextMenu(ctx, x, y);
            ctx.hideContextMenu       = ()       => hideContextMenu(ctx);
            ctx.updatePreview         = ()       => updatePreview(ctx);
            ctx.updateStatus          = ()       => updateStatus(ctx);
            ctx.setMode               = (m)      => setMode(ctx, m);
            ctx.toggleFullscreen      = ()       => toggleFullscreen(ctx);
            ctx.getCurrentMarkdown    = ()       => getCurrentMarkdown(ctx);
            ctx.applyMarkdown         = (md)     => applyMarkdown(ctx, md);

            // ── History / auto-save bridges ──
            ctx.readBook              = ()       => readBook(ctx.config, razyui);
            ctx.writeBook             = (book)   => writeBook(ctx.config, book);
            ctx.readHistory           = ()       => readHistory(ctx.config, razyui);
            ctx.pushHistory           = (md)     => pushHistoryEntry(ctx.config, razyui, md);
            ctx.deleteHistoryEntry    = (idx)    => deleteHistoryEntry(ctx.config, razyui, idx);
            ctx.clearActiveHistory    = ()       => clearActiveHistory(ctx.config, razyui);
            ctx.startAutoSave         = ()       => startAutoSave(ctx);
            ctx.stopAutoSave          = ()       => stopAutoSave(ctx);
            ctx.showHistoryRestorePopup = ()     => showHistoryRestorePopup(ctx);
            ctx.showHistoryManagerPopup = ()     => showHistoryManagerPopup(ctx);
            ctx.bindHistoryRestoreEvents = (overlay, refs) => bindHistoryRestoreEvents(ctx, overlay, refs);
            ctx.bindHistoryManagerEvents = (wrap, refs)    => bindHistoryManagerEvents(ctx, wrap, refs);

            this.#_ctx = ctx;
        }
        return this.#_ctx;
    }

    // ── Constructor ──────────────────────────────
    /**
     * Creates a new MarkdownEditor instance.
     * @param {string|Element} selector - CSS selector or Element for a container / <textarea>.
     * @param {Object} [config={}] - Configuration options.
     * @param {string} [config.mode='split'] - 'split' | 'editor' | 'preview'.
     * @param {boolean} [config.toolbar=true] - Show toolbar.
     * @param {string} [config.placeholder] - Placeholder text for the editor.
     * @param {string} [config.value] - Initial markdown content.
     * @param {string} [config.height='auto'] - CSS height.
     * @param {string} [config.minHeight='360px'] - CSS min-height.
     * @param {Function} [config.onChange] - Callback triggered on content change.
     * @param {Function} [config.onSave] - Callback triggered on save.
     */
    constructor(selector, config = {}) {
        this.#config = { ...DEFAULTS, ...config };

        // Resolve target element
        const el = razyui(selector)[0];
        if (!el) {
            console.warn('MarkdownEditor: element not found \u2192', selector);
            return;
        }
        this.#target = el;

        // If the target is a <textarea>, read its value and replace it
        let initialValue = this.#config.value;
        if (el.tagName === 'TEXTAREA') {
            if (!initialValue && el.value) initialValue = el.value;
            this.#config.value = initialValue;
        }

        this.#init();
    }

    // ── Initialization ───────────────────────────
    #init() {
        const ctx = this.#ctx();

        // 1. Reactive state
        const { ref, setState } = createReactiveState(razyui.state, ctx.config);
        this.#stateRef = ref;
        this.#setState = setState;

        // 2. Build DOM (sets ctx.container, ctx.toolbar, etc.)
        buildDOM(ctx);

        // 3. Bind events
        bindEvents(ctx);

        // 4. Initial render (non-lite only)
        if (!ctx.config.lite) {
            ctx.updatePreview();
            ctx.updateStatus();
        }

        // 5. Auto-save
        if (ctx.config.autoSave && ctx.config.id) {
            ctx.startAutoSave();

            // Check for existing snapshots → offer restore
            const book = ctx.readBook();
            const hasSnapshots = Object.values(book.sets).some(s => s.snapshots.length > 0);
            if (hasSnapshots) {
                ctx.showHistoryRestorePopup();
            }
        }
    }

    // ═══════════════════════════════════════════════
    // Public API
    // ═══════════════════════════════════════════════

    /**
     * Returns a control object for programmatic interaction.
     * @returns {object}
     */
    getControl() {
        const ctx = this.#ctx();
        const isWysiwyg = () => ctx.config.lite || ctx.stateRef.mode === 'wysiwyg';

        return {
            /** 
             * Get the raw Markdown content 
             * @returns {string} The raw Markdown content.
             */
            getMarkdown: () => {
                if (isWysiwyg()) return htmlToMarkdown(ctx.preview.html());
                return ctx.textarea.value;
            },

            /** 
             * Set the Markdown content 
             * @param {string} md - The Markdown content to set.
             */
            setMarkdown: (md) => {
                if (isWysiwyg()) {
                    ctx.preview.html(parse(md));
                    ctx.onWysiwygInput();
                    return;
                }
                ctx.textarea.value = md;
                ctx.onInput();
            },

            /** 
             * Get the rendered HTML 
             * @returns {string} The rendered HTML.
             */
            getHtml: () => {
                if (isWysiwyg()) return ctx.preview.html();
                return parse(ctx.textarea.value);
            },

            /** 
             * Insert text at cursor position 
             * @param {string} text - The text to insert.
             */
            insertText: (text) => {
                if (isWysiwyg()) {
                    ctx.wysiwygInsertText(text);
                    ctx.onWysiwygInput();
                    return;
                }
                ctx.insertAtCursor(text);
                ctx.onInput();
            },

            /** 
             * Wrap selection with before/after strings 
             * @param {string} before - The string to insert before the selection.
             * @param {string} after - The string to insert after the selection.
             */
            wrapSelection: (before, after) => {
                if (isWysiwyg()) {
                    const sel = window.getSelection();
                    if (sel.rangeCount && !sel.isCollapsed) {
                        const range = sel.getRangeAt(0);
                        const text = range.toString();
                        range.deleteContents();
                        range.insertNode(document.createTextNode(before + text + after));
                    }
                    ctx.onWysiwygInput();
                    return;
                }
                ctx.wrapSelection(before, after);
                ctx.onInput();
            },

            /** 
             * Toggle a line prefix (heading, list, etc.) — textarea mode only 
             * @param {string} prefix - The prefix to toggle.
             */
            toggleLinePrefix: (prefix) => {
                if (isWysiwyg()) return;
                ctx.toggleLinePrefix(prefix);
                ctx.onInput();
            },

            /** 
             * Get the editable element (textarea or WYSIWYG contenteditable) 
             * @returns {Element} The editable element.
             */
            get textarea() { return ctx.textarea || ctx.preview; },

            /** 
             * Get the current selection 
             * @returns {Object} An object containing the start, end, and text of the selection.
             */
            getSelection: () => {
                if (isWysiwyg()) {
                    const sel = window.getSelection();
                    return { start: 0, end: 0, text: sel.toString() };
                }
                return {
                    start: ctx.textarea.selectionStart,
                    end: ctx.textarea.selectionEnd,
                    text: ctx.textarea.value.substring(ctx.textarea.selectionStart, ctx.textarea.selectionEnd),
                };
            },

            /** 
             * Focus the editor 
             */
            focus: () => {
                if (isWysiwyg()) { ctx.preview.focus(); return; }
                ctx.textarea.focus();
            },

            blur: () => {
                if (isWysiwyg()) { ctx.preview.blur(); return; }
                ctx.textarea.blur();
            },

            /** 
             * Change the view mode 
             * @param {string} mode - The view mode to set.
             */
            setMode: (mode) => ctx.setMode(mode),

            /** 
             * Toggle fullscreen 
             */
            toggleFullscreen: () => ctx.toggleFullscreen(),

            /** 
             * Get current mode 
             * @returns {string} The current view mode.
             */
            get mode() { return ctx.stateRef.mode; },

            /** 
             * Get/set disabled 
             * @returns {boolean} True if disabled, false otherwise.
             */
            get disabled() {
                return ctx.textarea
                    ? ctx.textarea.disabled
                    : (ctx.preview.contentEditable === 'false');
            },
            set disabled(val) {
                if (ctx.textarea) {
                    ctx.textarea.disabled = !!val;
                } else {
                    ctx.preview.contentEditable = val ? 'false' : 'true';
                }
                ctx.container.toggleClass('is-disabled', !!val);
                ctx.container[0].setAttribute('aria-disabled', String(!!val));
            },

            // ── Auto-save & History API ──

            /** 
             * Get the editor's unique ID 
             * @returns {string} The editor's unique ID.
             */
            get id() { return ctx.config.id; },

            /**
             * Get snapshots from the active set.
             * @returns {Array<{ts:number, date:string, md:string, hash:string}>} An array of snapshots.
             */
            getHistory: () => {
                return ctx.readHistory().map(entry => ({
                    ts: entry.ts,
                    date: new Date(entry.ts).toLocaleString(),
                    md: entry.md,
                    hash: entry.hash || '',
                }));
            },

            /**
             * Restore a specific snapshot by index in the active set.
             * @param {number} index — 0-based index (newest = last)
             * @returns {boolean} true if restored
             */
            restoreHistory: (index) => {
                const history = ctx.readHistory();
                if (index < 0 || index >= history.length) return false;
                ctx.applyMarkdown(history[index].md);
                return true;
            },

            /**
             * Restore the most recent snapshot in the active set.
             * @returns {boolean} true if restored
             */
            restoreLatest: () => {
                const history = ctx.readHistory();
                if (!history.length) return false;
                ctx.applyMarkdown(history[history.length - 1].md);
                return true;
            },

            /**
             * Clear all snapshots in the active set.
             */
            clearHistory: () => {
                ctx.clearActiveHistory();
            },

            /**
             * Delete a single snapshot by index in the active set.
             * @param {number} index
             * @returns {boolean}
             */
            deleteHistory: (index) => {
                return ctx.deleteHistoryEntry(index);
            },

            /**
             * Manually save the current content as a snapshot.
             * @returns {boolean} true if saved (false if content unchanged)
             */
            saveNow: () => {
                return ctx.pushHistory(ctx.getCurrentMarkdown());
            },

            /**
             * Open the history manager popup (view, restore, delete snapshots & sets).
             */
            showHistory: () => {
                ctx.showHistoryManagerPopup();
            },

            // ── Set Management API ──

            /**
             * Get all sets in the history book.
             * @returns {Array<{id:number, name:string, created:number, count:number, active:boolean}>} An array of history sets.
             */
            getSets: () => {
                const book = ctx.readBook();
                return Object.entries(book.sets).map(([id, s]) => ({
                    id: parseInt(id, 10),
                    name: s.name || 'Set ' + id,
                    created: s.created || 0,
                    count: s.snapshots.length,
                    active: String(book.activeSet) === id,
                }));
            },

            /** 
             * Get the active set ID 
             * @returns {number} The active set ID.
             */
            get activeSet() {
                return ctx.readBook().activeSet ?? 0;
            },

            /**
             * Switch the active set for auto-save.
             * @param {number} setId
             * @returns {boolean} true if switched
             */
            switchSet: (setId) => {
                const book = ctx.readBook();
                if (!book.sets[String(setId)]) return false;
                book.activeSet = setId;
                ctx.writeBook(book);
                return true;
            },

            /**
             * Create a new history set.
             * @param {string} [name] — optional name for the set
             * @returns {number} the new set's ID
             */
            createSet: (name) => {
                const book = ctx.readBook();
                const ids = Object.keys(book.sets).map(Number).filter(n => !isNaN(n));
                const newId = ids.length ? Math.max(...ids) + 1 : 0;
                book.sets[String(newId)] = { name: name || 'Set ' + newId, created: Date.now(), snapshots: [] };
                ctx.writeBook(book);
                return newId;
            },

            /**
             * Delete a history set by ID (cannot delete if it's the only set).
             * @param {number} setId
             * @returns {boolean} true if deleted
             */
            deleteSet: (setId) => {
                const book = ctx.readBook();
                const key = String(setId);
                if (!book.sets[key]) return false;
                if (Object.keys(book.sets).length <= 1) return false;
                delete book.sets[key];
                if (String(book.activeSet) === key) {
                    book.activeSet = parseInt(Object.keys(book.sets)[0], 10) || 0;
                }
                ctx.writeBook(book);
                return true;
            },

            /**
             * Rename a history set.
             * @param {number} setId
             * @param {string} name
             * @returns {boolean} true if renamed
             */
            renameSet: (setId, name) => {
                const book = ctx.readBook();
                const s = book.sets[String(setId)];
                if (!s) return false;
                s.name = name;
                ctx.writeBook(book);
                return true;
            },

            get label()       { return ctx.container[0].getAttribute('aria-label'); },
            set label(v)      { v ? ctx.container[0].setAttribute('aria-label', v) : ctx.container[0].removeAttribute('aria-label'); },
            get labelledby()  { return ctx.container[0].getAttribute('aria-labelledby'); },
            set labelledby(v) { v ? ctx.container[0].setAttribute('aria-labelledby', v) : ctx.container[0].removeAttribute('aria-labelledby'); },
            get describedby() { return ctx.container[0].getAttribute('aria-describedby'); },
            set describedby(v){ v ? ctx.container[0].setAttribute('aria-describedby', v) : ctx.container[0].removeAttribute('aria-describedby'); },

            destroy: () => this.destroy(),
            get element() { return ctx.container[0]; },
        };
    }

    /**
     * Destroy the editor and restore the original element.
     */
    destroy() {
        if (this.#destroyed) return;
        this.#destroyed = true;
        this.#eventAC?.abort();
        const ctx = this.#ctx();
        clearTimeout(ctx.updateTimer);
        ctx.stopAutoSave();
        ctx.hideContextMenu();

        if (ctx.target.tagName === 'TEXTAREA') {
            razyui(ctx.target).css('display', '');
        }
        ctx.container.remove();
    }
};

export default MarkdownEditor;
