/**
 * @fileoverview MarkdownEditor state — reactive state creation, auto-save,
 *               and localStorage-backed history management.
 *
 * Storage structure per editor id:
 *   localStorage["md-editor-{id}"] = {
 *     activeSet: 0,
 *     sets: {
 *       "0": { name: "Default", created: <ts>, snapshots: [ { ts, md, hash } ] },
 *       "1": { name: "Draft 2", created: <ts>, snapshots: [...] },
 *     }
 *   }
 *
 * @module module/MarkdownEditor/state
 */

import { contentHash } from './helpers.js';

// ═══════════════════════════════════════════════════
// Reactive State
// ═══════════════════════════════════════════════════

/**
 * Create the reactive state for a MarkdownEditor instance.
 *
 * @param {Function} stateFn — razyui.state
 * @param {object}   config  — resolved editor config
 * @returns {{ ref: object, setState: Function, stateSet: Array }}
 */
export function createReactiveState(stateFn, config) {
    const stateSet = stateFn({
        mode: config.lite ? 'wysiwyg' : config.mode,
        fullscreen: false,
        markdown: config.value || '',
    });
    return { ref: stateSet[0], setState: stateSet[1], stateSet };
}

// ═══════════════════════════════════════════════════
// Auto-save / History Helpers
// ═══════════════════════════════════════════════════

/**
 * Get the localStorage key for an editor instance.
 * @param {object} config
 * @returns {string|null}
 */
export function storageKey(config) {
    return config.id != null ? `md-editor-${config.id}` : null;
}

/**
 * Read the entire history book from localStorage.
 * Migrates legacy flat arrays automatically.
 * @param {object} config
 * @param {object} razyui
 * @returns {{ activeSet: number, sets: Object }}
 */
export function readBook(config, razyui) {
    const key = storageKey(config);
    if (!key) return { activeSet: 0, sets: {} };
    try {
        const raw = localStorage.getItem(key);
        if (!raw) return { activeSet: 0, sets: {} };
        const parsed = JSON.parse(raw);
        if (razyui.isPO(parsed) && parsed.sets) return parsed;
        // Migrate legacy flat array → set 0
        if (Array.isArray(parsed)) {
            const migrated = {
                activeSet: 0,
                sets: { '0': { name: 'Default', created: Date.now(), snapshots: parsed } },
            };
            writeBook(config, migrated);
            return migrated;
        }
        return { activeSet: 0, sets: {} };
    } catch {
        return { activeSet: 0, sets: {} };
    }
}

/**
 * Write the entire history book to localStorage.
 * @param {object} config
 * @param {object} book
 */
export function writeBook(config, book) {
    const key = storageKey(config);
    if (!key) return;
    try {
        localStorage.setItem(key, JSON.stringify(book));
    } catch { /* storage full */ }
}

/**
 * Get the active set object (creates default set 0 if missing).
 * @param {object} config
 * @param {object} razyui
 * @returns {{ name: string, created: number, snapshots: Array }}
 */
export function getActiveSet(config, razyui) {
    const book = readBook(config, razyui);
    const id = String(book.activeSet ?? 0);
    if (!book.sets[id]) {
        book.sets[id] = { name: 'Default', created: Date.now(), snapshots: [] };
        writeBook(config, book);
    }
    return book.sets[id];
}

/**
 * Read snapshots from the active set.
 * @param {object} config
 * @param {object} razyui
 * @returns {Array<{ts:number, md:string, hash:string}>}
 */
export function readHistory(config, razyui) {
    return getActiveSet(config, razyui).snapshots || [];
}

/**
 * Push a snapshot into the active set.
 * Skips if content hash matches the last snapshot (change detection).
 * @param {object} config
 * @param {object} razyui
 * @param {string} markdown
 * @returns {boolean} true if a new snapshot was actually saved
 */
export function pushHistoryEntry(config, razyui, markdown) {
    const key = storageKey(config);
    if (!key) return false;

    const hash = contentHash(markdown);
    const book = readBook(config, razyui);
    const setId = String(book.activeSet ?? 0);
    if (!book.sets[setId]) {
        book.sets[setId] = { name: 'Default', created: Date.now(), snapshots: [] };
    }
    const snaps = book.sets[setId].snapshots;

    // Change detection: skip if hash matches last snapshot
    if (snaps.length && snaps[snaps.length - 1].hash === hash) return false;

    snaps.push({ ts: Date.now(), md: markdown, hash });

    // Trim to max
    const max = config.autoSaveMax;
    if (snaps.length > max) snaps.splice(0, snaps.length - max);

    writeBook(config, book);
    return true;
}

/**
 * Delete a single snapshot by index in the active set.
 * @param {object} config
 * @param {object} razyui
 * @param {number} index
 * @returns {boolean}
 */
export function deleteHistoryEntry(config, razyui, index) {
    const book = readBook(config, razyui);
    const setId = String(book.activeSet ?? 0);
    const snaps = book.sets[setId]?.snapshots;
    if (!snaps || index < 0 || index >= snaps.length) return false;
    snaps.splice(index, 1);
    writeBook(config, book);
    return true;
}

/**
 * Clear all snapshots in the active set.
 * @param {object} config
 * @param {object} razyui
 */
export function clearActiveHistory(config, razyui) {
    const book = readBook(config, razyui);
    const setId = String(book.activeSet ?? 0);
    if (book.sets[setId]) {
        book.sets[setId].snapshots = [];
        writeBook(config, book);
    }
}

/**
 * Start the auto-save interval timer.
 * @param {object} ctx — context bridge
 */
export function startAutoSave(ctx) {
    stopAutoSave(ctx);
    const interval = Math.max(1000, ctx.config.autoSaveInterval);
    ctx.autoSaveTimer = setInterval(() => {
        const md = ctx.getCurrentMarkdown();
        ctx.pushHistory(md);
    }, interval);
}

/**
 * Stop the auto-save interval.
 * @param {object} ctx — context bridge
 */
export function stopAutoSave(ctx) {
    if (ctx.autoSaveTimer) {
        clearInterval(ctx.autoSaveTimer);
        ctx.autoSaveTimer = null;
    }
}
